INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00074', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「想要在新 IT 產業占有一席之地，真正關鍵的課題是如何投資想像力，並非天馬行空的科幻內容， 而是創造未來美好生活方式的能力。演算法、機器人、基因工程、腦神經學、奈米技術、延展實境等 科技的進步，正在全面改造世界。在科技的衝擊下，未來生活的樣貌充滿許多想像的可能性。同時， 在科技的實現下，想像將會成為一種可以具體體驗的生活方式。」 根據上文，下列選項正確的是：', '["科幻小說預告未來世界", "虛擬實境實現時空穿越", "IT產業改變投資的風險", "科技進步實現未來想像"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00075', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「臺灣飲食向來有其獨特的魅力，賣包子、饅頭、刀削麵的店家往往與米粉、碗粿、肉圓並列一條街， 來客也不分族群，無論祖上是山東、臺南或是客家。我們的川菜沒有四川吃的那麼辣那麼油，所謂的 『川味牛肉麵』也創始於臺灣。廿年前，誰想得到臺灣的『珍珠奶茶』會流傳到世界各地，還常常附 帶賣些『大腸包小腸』這種聽起來特殊的小吃。」 根據上文，下列選項何者正確？', '["世風日下，菜餚遠離原始風貌，令人惋惜", "各系菜色的變化與創始淵源有絕對的關係", "臺灣飲食的獨特風貌，和族群融合多元並蓄有密切的關係", "符合地緣時令又有原創性的飲食，是一種狹義的劃地自限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00076', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「茶是飲品，渴則飲，但品茶往往不是為了解渴，而上升到精神文明的層次。自明代後，品茶有色、 香、味之說，色尚綠，綠是茶的真色，也是生命之色、自然之色。香尚淡，淡而微，微而悠，悠而玄， 玄而入韻，其香方可通於清幽之境，茶味在甘苦之外；離甘苦而合於中，才是茶的真味。」 根據上文，下列選項何者最接近「茶的真味」？', '["香氣襲人、微帶苦澀", "入喉清雅、餘韻回甘", "沁鼻陳香、醇厚悠玄", "湯色澄澈、微量加糖"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00077', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「杜甫是中國歷代大詩人中最不輕易放棄任何傳統的詩人，從表面看，他那種雄渾博大的風格，那種 熱烈擁抱現實的精神，與六朝時期專門講究小巧纖細的作品，相去甚遠。但事實上，他從傳統與六朝 都學到了許許多多的技巧。」 根據上文，下列選項最足以說明文意的是：', '["尺有所短，寸有所長", "學如不及，猶恐失之", "轉益多師，兼容並蓄", "旁徵博引，左右逢源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00078', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「閱讀一本書應該像是你與作者之間的對話，有關這個主題，他知道的應該比你還多，否則你根本用 不著去跟這本書打交道了。但是了解是一種雙向溝通的過程，學生必須要向自己提問題，也要向老師 提問題。一旦他了解老師的說法後，還要能夠跟老師爭辯。」 根據上文，下列選項最符合文意的是：', '["閱讀如上課，若不能勇於提問就無法掌握知識", "閱讀時若能學習爭辯，必然能與老師雙向溝通", "閱讀不是單純的知識學習，更是與作者的對話", "閱讀如與書本打交道，打破主題與知識的限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00079', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「我發現自己追尋內心更大的痛楚，因為那可以讓我忘掉原來的痛楚，這使我想起牙痛的經驗——我 們通常會想讓牙更痛一些，以此作為一種舒緩。原來，痛本身就可以治療痛。」 下列選項，何者最符合文意？', '["更嚴重的痛竟可以治療痛", "痛楚的程度令人無法想像", "沒有任何方法可以忘掉痛", "痛的舒緩方法就是忽視痛"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00080', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「羅馬的偉人凱撒大帝是被他的部下布魯特斯刺死的。凱撒死後，他的另一個部下安東尼要求到廣場 去向人民發表追悼演說，布魯特斯答應了。可是附有一個條件：『不能說我們的壞話。』安東尼接受 了這個條件，他在演說中屢次聲明布魯特斯是個正人君子，但是，民眾聽他講完了，掀起一陣風暴， 非要殺死布魯特斯不可。因為他喝的是倒采。」 根據上文，敘述正確的是：', '["布魯特斯成功吸收安東尼在追悼會上發表演講", "安東尼實踐不能說壞話的約定卻造成部下反彈", "喝倒采在此指的是安東尼的演說差勁令人反感", "民眾想殺死布魯特斯的念頭符合安東尼的期望"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00081', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「從根源上說，文藝復興時代的藝術家的努力確曾大大地促進了近代科學的興起。但在進一步的發展 過程中，科學與藝術遂不能不分道揚鑣。這是由於藝術家對科學知識的態度完全與科學家不同的緣故。 前者用人的概念與情感來處理科學知識，故在運用時不能完全精確；後者則純用理性來探求自然的真 象，其間不滲雜絲毫人的因素，故能精益求精。」 根據上文，下列選項最符合文意的是：', '["藝術與科學的扞格肇自文藝復興時代", "藝術家往往不擅長於精確縝密的思考", "科學知識的特質乃是摒除人類的情感", "科學家常用理性態度來進行藝術創作"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00082', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「在超商排隊是我最有感的事情，我其實不太能忍受花上三分鐘等待餐點、咖啡或結帳，就算是我願 意等，心裡也是百般折磨。一來是，當我使用像超商這樣的商店時，我預期它就是會非常迅速地結帳 並且拿到我想買的東西；但是另一方面，有時候我更覺得是想取得自己對時間的掌控權。」 根據上文，下列選項最符合文意的是：', '["超商的結帳程序，總是能夠符合作者的想法", "超商提供便利快捷的服務，讓作者備受禮遇", "超商多樣化商品，讓作者易取得想買的東西", "藉超商的快速服務，作者預期可以爭取時間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00083', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「文學宜講究天真自然，若能把生活中靜觀或微悟化為文字，必然能感動在日常裡辛勞奔波的讀者。 不過人生何其平凡，要將人人都懂的酸甜苦澀，提升為可供品味的文學，作家除了文藝技巧的嫻熟， 最主要必須有過人的處世意境，才能在常人忽略的事物中，得到發人深省的延伸思考。」 根據上文，作家最須具備的特質是：', '["天真自然的本性", "嫻熟的文藝技巧", "酸甜苦澀的人生", "處世的靜觀微悟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
